module top_module(clk, load, addr, d, q);parameter DWIDTH=16,AWIDTH=12,WORDS=4096;


 input clk,load;
 input [AWIDTH-1:0] addr;
 input [DWIDTH-1:0] d;
 output [DWIDTH-1:0] q;
 reg [DWIDTH-1:0] q;
 reg [DWIDTH-1:0] mem [WORDS-1:0];

   wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
   begin
     if(load) mem[addr] <= d;
     q <= mem[addr];
   end

endmodule
